import * as React from "react";

import { cn } from "../utils/cn";

type LiveModeButtonProps = {
  /** Whether live mode is currently enabled. */
  enabled?: boolean;
  /** Called when the button is toggled. */
  onToggle?: () => void;
  /** Whether to show the "Live View" label text. Hidden on mobile by default. */
  showLabel?: boolean;
  /** Whether to show the circular progress indicator around the icon. */
  showProgress?: boolean;
  /** Progress value from 0 to 100 for the circular indicator. */
  progress?: number;
  className?: string;
};

/**
 * A live mode toggle button matching the Vue V2 LiveMode component.
 *
 * Displays a pulsing dot icon (red when inactive, green with pulse animation
 * when active). When enabled, the button switches to the active style with
 * primary-100 background and primary-500 border.
 *
 * Optionally renders a circular progress SVG around the icon to indicate
 * the refresh interval.
 */
function LiveModeButton({
  enabled = false,
  onToggle,
  showLabel = true,
  showProgress = false,
  progress = 0,
  className,
}: LiveModeButtonProps) {
  return (
    <button
      type="button"
      data-slot="live-mode-button"
      onClick={onToggle}
      className={cn(
        "inline-flex h-[44px] min-w-[44px] items-center gap-1.5 rounded border px-2 text-sm font-normal",
        "transition-colors",
        enabled
          ? "border-brand-primary-500 bg-brand-primary-100 text-brand-primary-500"
          : "border-brand-grey-400 bg-white text-brand-grey-800",
        className,
      )}
    >
      <span className="relative flex shrink-0 items-center justify-center">
        {/* Dot icon matching mdi-access-point */}
        <svg
          className={cn(
            "h-5 w-5",
            enabled
              ? "text-green-600 animate-[live-pulse_1s_infinite]"
              : "text-red-500",
          )}
          viewBox="0 0 24 24"
          fill="currentColor"
          aria-hidden="true"
        >
          <circle cx="12" cy="12" r="4" />
          <path
            d="M7.05 7.05a7 7 0 0 0 0 9.9M16.95 7.05a7 7 0 0 1 0 9.9M4.22 4.22a11 11 0 0 0 0 15.56M19.78 4.22a11 11 0 0 1 0 15.56"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
          />
        </svg>

        {/* Circular progress indicator */}
        {showProgress && enabled && (
          <svg
            className="absolute"
            width="30"
            height="30"
            viewBox="0 0 30 30"
            aria-hidden="true"
          >
            <circle
              cx="15"
              cy="15"
              r="12"
              strokeWidth="3"
              fill="none"
              stroke="#e0e0e0"
            />
            <circle
              cx="15"
              cy="15"
              r="12"
              strokeWidth="3"
              fill="none"
              stroke="var(--color-brand-primary-300, #93c5fd)"
              strokeLinecap="round"
              strokeDasharray={`${(progress * 75.4) / 100} ${75.4 - (progress * 75.4) / 100}`}
              transform="rotate(-90 15 15)"
              style={{ transition: "stroke-dasharray 0.3s linear" }}
            />
          </svg>
        )}
      </span>

      {showLabel && <span className="hidden xl:inline">Live View</span>}
    </button>
  );
}

export { LiveModeButton };
export type { LiveModeButtonProps };
